update wms_purchase_order
order_no = #{orderNo}, supplier_id = #{supplierId}, purchase_date = #{purchaseDate}, total_amount = #{totalAmount}, status = #{status}, remark = #{remark}, create_by = #{createBy}, create_time = #{createTime}, update_by = #{updateBy}, update_time = #{updateTime},
where purchase_order_id = #{purchaseOrderId}

update wms_purchase_order
set status = #{newStatus},
    update_by = #{updateBy},
    update_time = sysdate()
where purchase_order_id = #{purchaseOrderId}
  and status = #{oldStatus}
